  Act0ShellStateV1 stateWithNoCompletedPractice() {
    final sample = Act0ShellStateV1.sample;
    final world1 = sample.worldById('world_1');
    final lessons = <Act0LessonCardV1>[
      for (var i = 0; i < world1.lessons.length; i++)
        world1.lessons[i].copyWith(
          state: i == 0 ? Act0LessonStateV1.current : Act0LessonStateV1.locked,
          isSelectable: i == 0,
          isLocked: i != 0,
        ),
    ];
    final worlds = <Act0WorldCardV1>[
      world1.copyWith(
        status: Act0WorldStateV1.current,
        isSelectable: true,
        isLocked: false,
        lessons: lessons,
      ),
    ];
    return stateWithWorlds(selectedWorldId: 'world_1', worlds: worlds);
  }

  Act0ShellStateV1 stateWithLessonCurrentV1({
    required String currentLessonId,
    String? progressLabel,
  }) {
    final sample = Act0ShellStateV1.sample;
    final world1 = sample.worldById('world_1');
    final currentIndex = world1.lessons.indexWhere(
      (lesson) => lesson.lessonId == currentLessonId,
    );
    assert(currentIndex >= 0);
    final lessons = <Act0LessonCardV1>[
      for (var i = 0; i < world1.lessons.length; i++)
        world1.lessons[i].copyWith(
          state: world1.lessons[i].lessonId == currentLessonId
              ? Act0LessonStateV1.current
              : i < currentIndex
              ? Act0LessonStateV1.completed
              : Act0LessonStateV1.locked,
          isSelectable: i <= currentIndex,
          isLocked: i > currentIndex,
        ),
    ];
    final worlds = <Act0WorldCardV1>[
      world1.copyWith(
        status: Act0WorldStateV1.current,
        progressLabel: progressLabel ?? '$currentIndex of 9 lessons complete',
        isSelectable: true,
        isLocked: false,
        lessons: lessons,
      ),
    ];
    return stateWithWorlds(selectedWorldId: 'world_1', worlds: worlds);
  }

  Act0ShellStateV1 stateWithPositionsCurrentV1() {
    return stateWithLessonCurrentV1(
      currentLessonId: 'positions',
      progressLabel: '4 of 9 lessons complete',
    );
  }

  Act0ShellStateV1 stateWithReviewMistakeV1({
    required Act0MistakeCardV1 mistake,
    required String selectedWorldId,
  }) {
    final sample = Act0ShellStateV1.sample;
    final selectedWorldBase = sample.worldById(selectedWorldId);
    final selectedWorld = selectedWorldBase.copyWith(
      status: Act0WorldStateV1.current,
      isSelectable: true,
      isLocked: false,
      lessons: <Act0LessonCardV1>[
        for (var i = 0; i < selectedWorldBase.lessons.length; i++)
          selectedWorldBase.lessons[i].copyWith(
            state: i == 0
                ? Act0LessonStateV1.current
                : selectedWorldBase.lessons[i].state,
            isSelectable: i == 0 || selectedWorldBase.lessons[i].isSelectable,
            isLocked: i == 0 ? false : selectedWorldBase.lessons[i].isLocked,
          ),
      ],
    );
    final worlds = <Act0WorldCardV1>[
      for (final world in sample.worlds)
        world.worldId == selectedWorldId ? selectedWorld : world,
    ];
    return Act0ShellStateV1(
      courseTitle: sample.courseTitle,
      courseSubtitle: sample.courseSubtitle,
      levelLabel: sample.levelLabel,
      xp: sample.xp,
      xpTarget: sample.xpTarget,
      streakDays: sample.streakDays,
      dailyGoalLabel: sample.dailyGoalLabel,
      dailyGoalValue: sample.dailyGoalValue,
      pathProgressLabel: sample.pathProgressLabel,
      selectedWorldId: selectedWorldId,
      worlds: worlds,
      lessons: selectedWorld.lessons,
      review: Act0ReviewStateV1(
        title: sample.review.title,
        subtitle: sample.review.subtitle,
        weaknessLabel: mistake.weaknessLabel,
        reason: mistake.reason,
        stats: sample.review.stats,
        chosenLabel: mistake.selectedLabel,
        betterLabel: mistake.betterLabel,
        mistakes: <Act0MistakeCardV1>[mistake],
      ),
      profile: sample.profile,
    );
  }

  Future<void> openFullTheoryRecallIdeaV1(WidgetTester tester) async {
    expect(
      find.byKey(const Key('act0_shell_theory_recall_sheet')),
      findsOneWidget,
    );
    expect(
      find.byKey(const Key('act0_shell_hint_body')).evaluate().isNotEmpty ||
          find
              .byKey(const Key('act0_shell_theory_recall_body'))
              .evaluate()
              .isNotEmpty,
      isTrue,
    );
    final fullIdeaCta = find.byKey(
      const Key('act0_shell_review_full_idea_cta'),
    );
    if (fullIdeaCta.evaluate().isNotEmpty) {
      await tester.tap(fullIdeaCta);
      await tester.pumpAndSettle();
    }
    expect(
      find.byKey(const Key('act0_shell_theory_recall_body')),
      findsOneWidget,
    );
  }

