  test('Controlled demo capture query accepts named safe surfaces only', () {
    final placement = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse('http://127.0.0.1:7357/?act0_capture=placement'),
    );
    expect(placement, isNotNull);
    expect(placement!.mode, Act0ControlledDemoCaptureModeV1.walkthrough);
    expect(placement.surface, Act0ControlledDemoCaptureSurfaceV1.placement);

    final review = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse('http://127.0.0.1:7357/?act0_capture=review'),
    );
    expect(review, isNotNull);
    expect(review!.mode, Act0ControlledDemoCaptureModeV1.directState);
    expect(review.surface, Act0ControlledDemoCaptureSurfaceV1.review);

    final firstCorrectFeedback = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse(
        'http://127.0.0.1:7357/?act0_capture=runner_first_correct_feedback',
      ),
    );
    expect(firstCorrectFeedback, isNotNull);
    expect(
      firstCorrectFeedback!.mode,
      Act0ControlledDemoCaptureModeV1.directState,
    );
    expect(
      firstCorrectFeedback.surface,
      Act0ControlledDemoCaptureSurfaceV1.runnerFirstCorrectFeedback,
    );

    final firstWrongFeedback = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse(
        'http://127.0.0.1:7357/?act0_capture=runner_first_wrong_feedback',
      ),
    );
    expect(firstWrongFeedback, isNotNull);
    expect(
      firstWrongFeedback!.mode,
      Act0ControlledDemoCaptureModeV1.directState,
    );
    expect(
      firstWrongFeedback.surface,
      Act0ControlledDemoCaptureSurfaceV1.runnerFirstWrongFeedback,
    );

    final repairFocus = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse('http://127.0.0.1:7357/?act0_capture=repair_focus'),
    );
    expect(repairFocus, isNotNull);
    expect(repairFocus!.mode, Act0ControlledDemoCaptureModeV1.directState);
    expect(repairFocus.surface, Act0ControlledDemoCaptureSurfaceV1.repairFocus);

    final repairResult = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse('http://127.0.0.1:7357/?act0_capture=repair_result'),
    );
    expect(repairResult, isNotNull);
    expect(repairResult!.mode, Act0ControlledDemoCaptureModeV1.directState);
    expect(
      repairResult.surface,
      Act0ControlledDemoCaptureSurfaceV1.repairResult,
    );

    final sessionRepair = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse('http://127.0.0.1:7357/?act0_capture=session_repair'),
    );
    expect(sessionRepair, isNotNull);
    expect(sessionRepair!.mode, Act0ControlledDemoCaptureModeV1.directState);
    expect(
      sessionRepair.surface,
      Act0ControlledDemoCaptureSurfaceV1.sessionRepair,
    );

    final legacyRunner = parseAct0ControlledDemoHarnessEntryV1(
      Uri.parse(
        'http://127.0.0.1:7357/?act0_capture=runner&world=world_1&lesson=what_poker_is&task=what_poker_is_theory',
      ),
    );
    expect(legacyRunner, isNotNull);
    expect(
      legacyRunner!.surface,
      Act0ControlledDemoCaptureSurfaceV1.runnerTheory,
    );

    expect(
      parseAct0ControlledDemoHarnessEntryV1(
        Uri.parse('http://127.0.0.1:7357/?act0_capture=runner&world=world_1'),
      ),
      isNull,
    );
