  testWidgets('Block summary locks continue below accuracy threshold', (
    tester,
  ) async {
    var continued = 0;
    var replayed = 0;
    var backedToMap = 0;

    await pumpCompact(
      tester,
      MaterialApp(
        home: Scaffold(
          body: Act0BlockCompletionShellV1(
            summary: const Act0BlockCompletionSummaryV1(
              lessonTitle: 'Button open basics',
              xpEarned: 18,
              errorCount: 3,
