              startLevel: 1,
              endLevel: 1,
              startXp: 42,
              endXp: 60,
              xpTarget: 200,
              nextLessonTitle: 'Facing a limp',
            ),
            onReplay: () {
              replayed += 1;
            },
            onContinue: () {
              continued += 1;
            },
            onBackToMap: () {
              backedToMap += 1;
            },
          ),
        ),
      ),
    );

    expect(find.textContaining('Need 80% accuracy'), findsOneWidget);
    expect(find.text('Almost there - replay to unlock'), findsOneWidget);
    expect(find.text('Lesson complete'), findsNothing);
    expect(
