      tester,
      MaterialApp(
        home: Scaffold(
          body: ValueListenableBuilder<Act0RunnerStateV1>(
            valueListenable: notifier,
            builder: (context, runner, _) {
              return Act0LessonRunnerShellV1(
                runner: runner,
                tableVisualVariant: Act0ShellTableVisualVariantV1.refinedDev2,
                onBack: () {},
                onContinueTheory: () {},
                onChooseOption: (_) {},
                onContinueReview: () {},
              );
            },
          ),
        ),
      ),
    );

