      expect(find.text('SB'), findsWidgets);
      expect(find.text('BB'), findsWidgets);
      expect(find.text('0.5 BB'), findsWidgets);
      expect(find.text('1 BB'), findsWidgets);

      final supportFinder = find.byKey(
