        support.data!.replaceAll(RegExp(r'\s+'), ' ').trim(),
        blindSeatSegments.first.replaceAll(RegExp(r'\s+'), ' ').trim(),
      );
      expect(supportPainter.computeLineMetrics().length, lessThanOrEqualTo(3));
